+
+describe("conditional options", () => {
+  it("resolves a dependency by object key or CLI flag", () => {
+    const parser = object({
+      mode: option("--mode", choice(["dev", "prod"] as const)),
+      config: requiredWhen({ option: "mode", value: "prod" }, "--config"),
+    });
+    const byKey = parseSync(parser, ["--mode", "dev"]);
+    assert.ok(!byKey.success);
