+    const byFlag = parseSync(object({
+      mode: option("--mode", choice(["dev", "prod"] as const)),
+      config: requiredWhen({ option: "--mode", value: "prod" }, "--config"),
+    }), ["--mode", "prod"]);
+    assert.ok(byFlag.success);
+  });
+
+  it("keeps optional dependencies hidden while allowing absent dependees", () => {
+    const parser = object({
+      enabled: option("--enabled", choice(["", "yes"] as const)),
+      detail: withDefault(conditionalOption("enabled", "--detail"), false),
